class Solution {
    public String sortString(String s) {
        StringBuilder result = new StringBuilder();
        int minIndex = findMinIndex(s);
        int maxIndex = findMaxIndex(s);
        while (minIndex != -1 || maxIndex != -1) {
            result.append(s.charAt(minIndex));
            minIndex = findMinIndex(s);
            maxIndex = findMaxIndex(s);
        }
        return result.toString();
    }

    private int findMinIndex(String s) {
        int minIndex = Integer.MAX_VALUE;
        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) < minIndex) {
                minIndex = s.charAt(i);
            }
        }
        return minIndex;
    }

    private int findMaxIndex(String s) {
        int maxIndex = Integer.MIN_VALUE;
        for (int i = s.length() - 1; i >= 0; i--) {
            if (s.charAt(i) > maxIndex) {
                maxIndex = s.charAt(i);
            }
        }
        return maxIndex;
    }
}
